task_name = #{taskName}, start_warehouse_id = #{startWarehouseId}, start_warehouse_name = #{startWarehouseName}, end_warehouse_id = #{endWarehouseId}, end_warehouse_name = #{endWarehouseName}, start_time = #{startTime}, end_time = #{endTime}, remark = #{remark}, priority = #{priority}, update_time = NOW()
