UPDATE task
task_name = #{taskName}, vehicle_id = #{vehicleId}, vehicle_plate = #{vehiclePlate}, driver_id = #{driverId}, driver_name = #{driverName}, start_warehouse_id = #{startWarehouseId}, start_warehouse_name = #{startWarehouseName}, end_warehouse_id = #{endWarehouseId}, end_warehouse_name = #{endWarehouseName}, status = #{status}, start_time = #{startTime}, end_time = #{endTime}, actual_start_time = #{actualStartTime}, actual_end_time = #{actualEndTime}, remark = #{remark}, priority = #{priority}, update_time = NOW()
