mapper.select:
SELECT * FROM task

    
        AND status = #{status}
    
    
        AND vehicle_id = #{vehicleId}
    
    
        AND driver_id = #{driverId}
    
    
        AND task_name LIKE CONCAT('%', #{taskName}, '%')
    
    
        AND start_time >= #{startTime}
    
    
        AND end_time <= #{endTime}
    

ORDER BY create_time DESC
LIMIT #{limit} OFFSET #{offset}
